class User:
  def __init__(self, name, role):
    self.name = name
    self.role = role

  def __repr__(self):
    return f'User(name={self.name!r}, role={self.role!r})'

  def __str__(self):
    return f'{self.name} ({self.role})'

u = User('Alice', 'admin')
print(repr(u))
print(str(u))

